insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('b37c094b-a1a9-4031-a2ac-1ab7532cd520', 'cb59b415-d9d2-41e4-8204-3b9ef991e6a7', null, '合格者A', null, '#0057B8', '山口大学の面接では「なぜ今の職業を辞めて医師を目指すのか」を必ず聞かれます。準備しておくといいです。', false, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('e1b1f7dc-9412-4250-852c-4326078ef4ef', 'cb59b415-d9d2-41e4-8204-3b9ef991e6a7', null, '受験生B', null, '#7C3AED', '筑波の統計問題、オッズ比の計算が毎年出てますよね？', false, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('d60e06ff-0585-45a2-89ea-5dbba2559fa2', 'cb59b415-d9d2-41e4-8204-3b9ef991e6a7', null, '@山田先生', null, '#0057B8', 'そうですね。P002の問題も参考にしてください。ROC曲線、カプランマイヤー曲線なども要チェックです。#生命科学', true, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('fc194b3b-253b-4e07-af7d-4327faa7c319', 'cb59b415-d9d2-41e4-8204-3b9ef991e6a7', null, '受験生C', null, '#00A86B', '長崎大学って生命科学600点配点ですか？それほぼ一本勝負じゃないですか笑', false, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('cb735d3d-f251-4656-81b6-28aa7bb533bb', 'cb59b415-d9d2-41e4-8204-3b9ef991e6a7', null, '合格者D（長崎）', null, '#EA580C', 'そうです！生命科学さえできれば受かります。でも問題の難易度は高くないので、基礎の完成度が鍵。', false, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('08c60335-7b31-485d-b67f-0593f8f9d6a7', '692f3b47-e15f-4735-9f53-6adf7d0de99b', null, '@鈴木先生', null, '#00A86B', '今日は細胞シグナリングのポイントをまとめます。RTK→Ras→MAPK経路は必須です。', true, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('43b246e3-df0e-4475-9e0c-944d07a36195', '692f3b47-e15f-4735-9f53-6adf7d0de99b', null, '受験生E', null, '#7C3AED', 'アポトーシスとネクローシスの違いは試験に出ますか？', false, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('d3a4d755-11e6-488e-9d53-77fdcdb17555', '692f3b47-e15f-4735-9f53-6adf7d0de99b', null, '@山田先生', null, '#0057B8', '大阪大学では頻出です。カスパーゼカスケード、シトクロムcの放出まで詳細に押さえておいてください。', true, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('bc65d91e-9fcb-4149-ad3b-405ed7aff33e', '12385772-539b-499b-a5a1-3581f9d3fae0', null, '合格者F（岡山）', null, '#EA580C', '岡山の面接では「医師不足についてどう思うか」が聞かれました。地域医療の話をするといいです。', false, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('b5b9d16d-faeb-46f5-9dc6-33234f16bd7c', '12385772-539b-499b-a5a1-3581f9d3fae0', null, '@田中先生', null, '#7C3AED', '面接では「Why medicine, why now?」を英語で聞かれる大学も増えています（浜松医科等）。必ず英語でも準備しておいてください。', true, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('ead2fb76-52ed-4833-aac0-02c44b5418fc', '3f325b0d-9a7c-4a22-873a-70d7ef8864c3', null, '@鈴木先生', null, '#00A86B', '【統計基礎】P値の解釈について：P値はH₀が正しいとした時に観察データ以上の差が生じる確率です。「差がある確率」ではないので注意！', true, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('ece98eb4-0205-49b5-809b-91d980abed59', '3f325b0d-9a7c-4a22-873a-70d7ef8864c3', null, '受験生G', null, '#0057B8', '筑波の2024年適性試験にベイズの定理が出ましたが、どこまで深く理解すれば良いですか？', false, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('49038e3a-9d07-4dc6-a047-c4ac6bf4325b', '3f325b0d-9a7c-4a22-873a-70d7ef8864c3', null, '@鈴木先生', null, '#00A86B', 'P(A|B) = P(B|A)P(A)/P(B) の公式と、感度・特異度・PPV・NPVの計算は完璧にしてください。P006の問題が典型例です。', true, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('ef3ad26e-b981-4ecb-960e-64d144c75aad', '9ca6877d-5624-4e4c-a41d-b9f9348ec9d3', null, '@田中先生', null, '#7C3AED', '今週のテーマ：医学英語語彙強化。epidemiology（疫学）、etiology（病因）、pathophysiology（病態生理）、prognosis（予後）を確認しましょう。', true, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('e63eaf78-ec01-447d-89b0-4d8e0b4fbfa2', '0a2475ba-c642-458c-8ccc-01590820a68b', null, '@佐藤先生', null, '#EA580C', '志望理由書の添削、今月は5名受け付けています。フォームからご連絡ください。合格実績：山口・岡山・名古屋など。', true, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('2b60b5ea-27bf-4721-8e60-405c52ce3eb9', '0a2475ba-c642-458c-8ccc-01590820a68b', null, '受験生H', null, '#0057B8', '志望理由書って何字書けばいいんでしょうか？大学によって違いますよね？', false, now());
insert into public.community_messages (id, channel_id, user_id, display_name, avatar_url, avatar_color, content, is_tutor, created_at) values ('a79ebed9-fe1e-453c-993c-0d512159b1fd', '0a2475ba-c642-458c-8ccc-01590820a68b', null, '@佐藤先生', null, '#EA580C', '大学によって異なりますが、800〜1500字が多いです。重要なのは「なぜ今？」「なぜその大学？」「入学後の計画」の3点を明確にすること。', true, now());
insert into public.problems (id, university_id, subject, year, difficulty, question, options, answer, answer_detail, is_premium) values ('845b63f9-a2c8-41e2-b353-e76a290983fb', 'ae02a640-431c-4721-b42d-acb32ae1de1f', '生命科学', 2025, 3, '真核細胞に存在して原核細胞に存在しない細胞小器官を3つ挙げ、それぞれの機能を簡潔に述べよ。', null, 'ミトコンドリア（好気呼吸・ATP産生）、ゴルジ体（タンパク質の修飾・輸送）、核膜（DNAの収容と保護）など。葉緑体（光合成）、リソソーム（細胞内消化）なども正解。', '原核細胞にはリボソームが存在するが、真核細胞のものとは構造が異なる（70S vs 80S）。膜系細胞小器官はすべて真核生物特有。', false);
insert into public.problems (id, university_id, subject, year, difficulty, question, options, answer, answer_detail, is_premium) values ('6d59c648-2171-4685-96e4-6c5bb062dc32', '4248a893-fd9a-45fe-b90a-951c2dcc8338', '生命科学', 2025, 4, '細胞膜を介した物質輸送には能動輸送と受動輸送がある。Na⁺/K⁺ポンプを例に、能動輸送の仕組みと生理的意義を述べよ。', null, 'Na⁺/K⁺-ATPaseはATPを加水分解するエネルギーを利用し、Na⁺を3個細胞外へ、K⁺を2個細胞内へ輸送する（濃度勾配に逆らう能動輸送）。この濃度勾配は神経・筋肉の興奮性、細胞容量調節、グルコース等の二次能動輸送に利用される。', 'Na⁺/K⁺ポンプはP型ATPaseの一種。阻害薬としてウアバイン（オウバイン）が有名。心不全治療薬ジゴキシンもNa⁺/K⁺ポンプを阻害することで薬効を発揮する。', true);
insert into public.problems (id, university_id, subject, year, difficulty, question, options, answer, answer_detail, is_premium) values ('013b42f0-1a3b-4198-bbae-47690b0c454c', 'd700e1bf-16ed-4d80-b1e1-a4de891d6b58', '生命科学', 2024, 3, 'mRNA、tRNA、rRNAのそれぞれの機能と、タンパク質合成（翻訳）における役割を説明せよ。', null, 'mRNA（メッセンジャーRNA）：遺伝情報をDNAから転写し、コドン配列でアミノ酸の順序を指定。tRNA（トランスファーRNA）：アンチコドンでmRNAのコドンと対合し、対応するアミノ酸をリボソームに運搬。rRNA（リボソームRNA）：リボソームの構造成分として翻訳の場を形成し、ペプチジルトランスフェラーゼ活性を担う。', 'リボソームは大サブユニット(60S)と小サブユニット(40S)から成る80S。細菌のリボソームは70Sで、抗菌薬の標的となる。', true);
insert into public.problems (id, university_id, subject, year, difficulty, question, options, answer, answer_detail, is_premium) values ('d590945a-b06f-447e-9eba-4cf9e6cf735f', 'dc318cd8-f27e-44df-bafc-5a52b8b2d5a7', '生命科学', 2025, 5, '癌細胞の特徴について、正常細胞との比較を交えながら、増殖制御・アポトーシス・エネルギー代謝の観点から論じよ。(英語で解答)', null, 'Cancer cells acquire unlimited proliferative potential by dysregulating the cell cycle (loss of RB, overactivation of cyclin/CDK), evading apoptosis (BCL-2 overexpression, p53 mutation), and shifting to aerobic glycolysis (Warburg effect) even in the presence of oxygen, supporting rapid biomass production.', '大阪大学は生命科学問題に英語が含まれることが特徴。Hallmarks of Cancer (Hanahan & Weinberg)の概念を押さえておくこと。', true);
insert into public.problems (id, university_id, subject, year, difficulty, question, options, answer, answer_detail, is_premium) values ('62820052-17ab-46b5-8b3b-1310443bebf3', 'b13d4650-6463-49b3-9e93-ff80fbe70baf', '生命科学', 2024, 4, 'DNA複製において、リーディング鎖とラギング鎖で複製の仕組みが異なる理由を、DNAポリメラーゼの特性と関連させて説明せよ。', null, 'DNAポリメラーゼは5''→3''方向にしかDNA合成できず、かつプライマーを必要とする。リーディング鎖は3''→5''の鋳型に対して5''→3''に連続合成が可能。ラギング鎖は5''→3''方向の鋳型に対して不連続なオカザキ断片として合成され、後にDNAリガーゼで連結される。', '複製開始にはRNAプライマーが必要。RNAプライマーはRNaseHで除去され、DNAポリメラーゼδで埋め合わせられる。', true);
insert into public.problems (id, university_id, subject, year, difficulty, question, options, answer, answer_detail, is_premium) values ('65f9e824-cbe9-4e4c-959c-100dd999084a', 'd700e1bf-16ed-4d80-b1e1-a4de891d6b58', '数学', 2025, 3, 'ある疾患の有病率が1%の集団において、感度95%・特異度90%の検査を施行した。陽性的中率（PPV）を求めよ。', null, 'ベイズの定理を使用。P(病気|陽性) = (感度×有病率) / (感度×有病率 + (1-特異度)×(1-有病率)) = (0.95×0.01) / (0.95×0.01 + 0.10×0.99) = 0.0095 / (0.0095 + 0.099) ≈ 0.0875 ≈ 8.75%', '有病率が低い集団では、高性能な検査でも陽性的中率は低くなることを示す重要な例。この結果は医療経済学・スクリーニングプログラム設計に直結する。', false);
insert into public.problems (id, university_id, subject, year, difficulty, question, options, answer, answer_detail, is_premium) values ('9b859339-13c0-4447-80e9-2b1fb4a688c5', 'b13d4650-6463-49b3-9e93-ff80fbe70baf', '数学', 2024, 4, '100名の患者を対象に薬剤Aと薬剤Bの効果を比較した。以下の2×2表からオッズ比と95%信頼区間を求め、統計学的有意性について述べよ。薬剤A: 有効35名・無効15名、薬剤B: 有効20名・無効30名', null, 'OR = (35×30) / (15×20) = 1050 / 300 = 3.5。ln(OR) = ln(3.5) ≈ 1.253。SE = √(1/35+1/15+1/20+1/30) ≈ 0.378。95%CI = exp(1.253 ± 1.96×0.378) = exp(0.512〜1.994) ≈ 1.67〜7.34。95%CIに1を含まないため統計学的に有意（p < 0.05）。', 'オッズ比の95%信頼区間は対数変換後に計算してから逆変換する。CIが1をまたがない場合は有意差あり。', true);
insert into public.problems (id, university_id, subject, year, difficulty, question, options, answer, answer_detail, is_premium) values ('e72e5823-ab08-421e-acb8-f1fa9a6f6660', '1b69d974-f655-4607-a1f4-341dac1dabfd', '数学', 2025, 3, '正規分布に従うとき、平均値±1.96標準偏差の範囲に含まれる確率は何%か。また、これを臨床研究における参照区間の設定にどう応用するか述べよ。', 'a:90% / b:95% / c:99% / d:68% / e:99.7%', 'b: 95%。正規分布では平均±1.96SDの範囲に全データの95%が含まれる（正確には95.0%）。参照区間（基準値範囲）の設定に応用：健常者集団の測定値の中央95%を「正常範囲」として採用。約5%の健常者が「異常値」として検出される（偽陽性5%）。', '参照区間の設定には通常120人以上の健常者データを使用（CLSI推奨）。非正規分布の場合は百分位数法を使用する。', false);
insert into public.problems (id, university_id, subject, year, difficulty, question, options, answer, answer_detail, is_premium) values ('74c3c685-5db5-4b61-8313-4a39b41117ba', '3264e2f6-7610-41ba-b591-b96ff1e84fee', '英語', 2025, 4, '次の英文を和訳せよ。"The gut microbiome has emerged as a pivotal mediator of the gut-brain axis, influencing neurotransmitter production, immune modulation, and the hypothalamic-pituitary-adrenal stress response."', null, '腸内マイクロバイオームは、腸脳軸の重要な仲介者として台頭しており、神経伝達物質の産生、免疫調節、および視床下部-下垂体-副腎（HPA）ストレス応答に影響を与えている。', 'gut-brain axis（腸脳軸）、hypothalamic-pituitary-adrenal axis（HPA軸）は頻出表現。mediator（仲介者）、modulation（調節）も重要語彙。', false);
insert into public.problems (id, university_id, subject, year, difficulty, question, options, answer, answer_detail, is_premium) values ('8d7336a8-1faa-4a70-a7a8-6a6f5e8cf1a6', '3a549969-7dd2-41d5-bbb4-ea294a9137b9', '英語', 2025, 3, 'あなたが医師を目指す理由を英語で200語程度で述べよ。', null, '【解答例】I aspire to become a physician because of a profound desire to alleviate human suffering. Growing up, witnessing my grandmother''s battle with cancer instilled in me a deep empathy for patients and their families. As a researcher, I have studied the molecular mechanisms of disease, yet I feel an urgent need to translate this knowledge into direct patient care. Medicine uniquely integrates scientific rigor with humanistic compassion. I am particularly drawn to internal medicine, where a physician must synthesize complex data while maintaining a holistic view of the patient as a person. I believe that the graduate-entry pathway will allow me to bring maturity, scientific depth, and genuine commitment to the medical profession.', '浜松医科大学では英語面接・英作文が重要。具体的なエピソードを盛り込み、将来像を明確に。TOEIC 700点以上が推奨。', true);
insert into public.problems (id, university_id, subject, year, difficulty, question, options, answer, answer_detail, is_premium) values ('563ed74b-d735-42fd-bc13-f1257bdb9314', '6d9e5203-4de6-4db8-930f-766f8e068a09', '化学', 2024, 4, 'グルコースの解糖系（前半・後半）について、関与する主要な酵素名と産物を記し、1分子のグルコースから何分子のATPが基質レベルリン酸化で産生されるか答えよ。', null, '前半（エネルギー投資相）：ヘキソキナーゼ、ホスホフルクトキナーゼ-1（PFK-1）などが働きATPを2分子消費。後半（エネルギー産生相）：ホスホグリセリン酸キナーゼとピルビン酸キナーゼが各1回ずつ基質レベルリン酸化を行い、1分子グルコースあたり4分子のATPを産生。正味産生ATP = 4 - 2 = 2分子。', '好気条件下ではミトコンドリアでのTCA回路・電子伝達系を経て計30〜32分子のATPが産生される。解糖系のみ（嫌気）では2 ATP + 2乳酸。', true);
insert into public.problems (id, university_id, subject, year, difficulty, question, options, answer, answer_detail, is_premium) values ('73995779-51f1-43e3-897e-17b62158a813', '3264e2f6-7610-41ba-b591-b96ff1e84fee', '化学', 2025, 3, 'タンパク質の4種類の構造（1次〜4次）を説明し、それぞれを安定化する化学的相互作用を列挙せよ。', null, '1次構造：アミノ酸配列（ペプチド結合で安定化）。2次構造：α-ヘリックス・β-シート（水素結合で安定化）。3次構造：1本のポリペプチド全体の立体構造（疎水性相互作用・ジスルフィド結合・水素結合・イオン結合・ファンデルワールス力）。4次構造：複数のサブユニットの集合形式（主に疎水性相互作用・水素結合）。', '変性（denaturation）は3次・4次構造の破壊で、1次構造（共有結合）は保たれる。熱・強酸・強塩基・界面活性剤（SDS）が変性を引き起こす。', true);
insert into public.problems (id, university_id, subject, year, difficulty, question, options, answer, answer_detail, is_premium) values ('227c8bd2-4956-4b60-bf95-5e9422ed8eb7', '29ecf120-4ff8-445d-be92-7bd690d9030c', '物理', 2024, 4, '心臓の拍動に伴う血圧波形（収縮期・拡張期）を流体力学的観点から説明し、脈圧と平均動脈圧（MAP）の計算式を示せ。', null, '収縮期に心室から血液が駆出されると大動脈壁が拡張し圧力が上昇（収縮期圧）。拡張期には弾性反跳により血流が維持され圧力は低下（拡張期圧）。脈圧 = 収縮期圧 - 拡張期圧。MAP ≈ 拡張期圧 + 脈圧/3 = 拡張期圧 + (収縮期圧 - 拡張期圧)/3。正常値：脈圧40mmHg、MAP70-100mmHg。', 'ポアズイユの法則：Q = πr⁴ΔP / (8ηL)。血管抵抗は半径の4乗に反比例するため、細動脈が主要な抵抗血管となる。', true);
insert into public.problems (id, university_id, subject, year, difficulty, question, options, answer, answer_detail, is_premium) values ('b3c9ed89-c53a-4b87-985d-fbf0f40016ae', 'ae02a640-431c-4721-b42d-acb32ae1de1f', '小論文', 2025, 4, '「医師の地域偏在問題について、あなたの考えを述べよ。」（600字、英語）Write an essay in English about the problem of geographical maldistribution of physicians in Japan.', null, '【解答例】 Japan faces a persistent challenge of physician maldistribution, with urban centers enjoying physician-to-population ratios far exceeding rural areas. This disparity creates equity concerns and burdens both patients and overworked rural physicians. Solutions include mandatory rural service periods for new graduates, telemedicine expansion, financial incentives for rural practitioners, and restructuring medical education to cultivate "community-oriented" physicians. As a graduate-entry medical student, I would be deeply committed to serving underserved communities, leveraging my prior professional experience to build trust with rural patients.', '山口大学は英語小論文が特徴的。地域医療・医師偏在は頻出テーマ。地域枠・医師少数区域（医療法施行規則）についても把握しておくこと。', true);
insert into public.problems (id, university_id, subject, year, difficulty, question, options, answer, answer_detail, is_premium) values ('8c82788a-3e73-4ff8-a4e8-2c5ba8157364', '4248a893-fd9a-45fe-b90a-951c2dcc8338', '小論文', 2024, 3, '「あなたが考える理想の医師像について述べよ。」（800字）', null, '【解答例の構成】①理想の医師像の提示（例：科学的思考力と人間的共感の両立）→②根拠となる経験・エピソード→③医学部進学後の具体的な学習計画→④社会への貢献の観点。
